<script>import'../../../../public/native-control.css';let cases=[{"label":"Accept terms"},{"label":"Email updates","checked":true},{"label":"Disabled","disabled":true},{"label":"Required","required":true}];</script><main class="native-shell"><h1>Checkbox</h1><section class="native-matrix">{#each cases as p}<label class="native-control checkbox" class:compact={p.compact}><input type="checkbox"  bind:checked={p.checked} disabled={p.disabled} required={p.required}/><span class="indicator" aria-hidden="true"></span><span>{p.label}</span></label>{/each}</section></main>